example.code:
// EMBED: user with bounded addresses (always accessed together)
{
  _id: ObjectId("..."),
  name: "John Doe",
  addresses: [
    { type: "home", street: "123 Main St", city: "NYC" },
    { type: "work", street: "456 Office Ave", city: "NYC" }
  ]
}

// REFERENCE: orders reference user (many orders per user)
{
  _id: ObjectId("..."),
  userId: ObjectId("user_id"),
  items: [{ productId: ObjectId("..."), name: "Widget", price: 29.99, qty: 2 }],
  totals: { subtotal: 59.98, tax: 4.80, total: 64.78 }
}

{
  sensorId: "temp-001",
  date: ISODate("2024-01-15"),
  measurements: [
    { ts: ISODate("2024-01-15T00:00:00Z"), value: 22.5 },
    { ts: ISODate("2024-01-15T00:05:00Z"), value: 22.7 }
    // ~200 measurements per doc
  ],
  summary: { count: 288, min: 21.2, max: 24.8, avg: 22.9 }
}

// Compound index for user's orders sorted by date
db.orders.createIndex({ userId: 1, createdAt: -1 });

// Partial index for pending orders only
db.orders.createIndex(
  { createdAt: 1 },
  { partialFilterExpression: { status: "pending" } }
);

// TTL index for automatic session expiry
db.sessions.createIndex({ createdAt: 1 }, { expireAfterSeconds: 3600 });
